from flask import Flask, request, jsonify
from elasticsearch import Elasticsearch

app = Flask(__name__)
es = Elasticsearch("http://localhost:9200")

@app.route("/aggregate", methods=["POST"])
def aggregate():
    req = request.get_json(force=True) or {}
    index = req.get("index", "default-index")
    field = req.get("field", "value")
    size = int(req.get("size", 10))

    body = {
        "size": 0,
        "aggs": {
            "dynamic_agg": {
                "terms": {
                    "field": field,
                    "size": size
                }
            }
        }
    }

    result = es.search(index=index, body=body)
    return jsonify(result)

@app.route("/cluster/settings", methods=["POST"])
def cluster_settings():
    body = {
        "persistent": {
            "script.allowed_types": "stored",
            "script.allowed_contexts": "score, update"
        }
    }
    result = es.cluster.put_settings(body=body)
    return jsonify(result)

if __name__ == "__main__":
    app.run(host="0.0.0.0", port=5000)